import React, { useState } from "react";
import { login } from "../services/authService";
import "./AuthPage.css";

/**
 * LoginPage
 * ─────────
 * Sign-in form. Accepts username OR email + password.
 *
 * Props:
 *   onLogin      {Function}  – called with the user object after successful login
 *   onGoRegister {Function}  – switches the view to the Register page
 */
function LoginPage({ onLogin, onGoRegister }) {
  const [form, setForm]       = useState({ username: "", password: "" });
  const [errors, setErrors]   = useState({});
  const [apiError, setApiError] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPwd, setShowPwd] = useState(false);

  const set = (field) => (e) => {
    setForm((prev) => ({ ...prev, [field]: e.target.value }));
    setErrors((prev) => ({ ...prev, [field]: "" }));
    setApiError("");
  };

  const validate = () => {
    const errs = {};
    if (!form.username.trim()) errs.username = "Username or email is required.";
    if (!form.password)        errs.password = "Password is required.";
    return errs;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }

    setLoading(true);
    try {
      const user = await login({ username: form.username.trim().toLowerCase(), password: form.password });
      onLogin(user);
    } catch (err) {
      setApiError(err.message || "Login failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        {/* Header */}
        <div className="auth-card__header">
          <span className="auth-card__icon">☑</span>
          <h1 className="auth-card__title">Sign In</h1>
          <p className="auth-card__subtitle">Welcome back! Please sign in to continue.</p>
        </div>

        {apiError && <div className="auth-alert auth-alert--error">{apiError}</div>}

        <form onSubmit={handleSubmit} noValidate className="auth-form">
          {/* Username / Email */}
          <div className={`auth-field ${errors.username ? "auth-field--error" : ""}`}>
            <label htmlFor="login-username">Username or Email</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">👤</span>
              <input
                id="login-username"
                type="text"
                placeholder="Enter your username or email"
                value={form.username}
                onChange={set("username")}
                autoComplete="username"
                autoFocus
              />
            </div>
            {errors.username && <p className="auth-field__error">{errors.username}</p>}
          </div>

          {/* Password */}
          <div className={`auth-field ${errors.password ? "auth-field--error" : ""}`}>
            <label htmlFor="login-password">Password</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">🔒</span>
              <input
                id="login-password"
                type={showPwd ? "text" : "password"}
                placeholder="Enter your password"
                value={form.password}
                onChange={set("password")}
                autoComplete="current-password"
              />
              <button
                type="button"
                className="auth-input-toggle"
                onClick={() => setShowPwd((v) => !v)}
                tabIndex={-1}
              >
                {showPwd ? "🙈" : "👁️"}
              </button>
            </div>
            {errors.password && <p className="auth-field__error">{errors.password}</p>}
          </div>

          <button type="submit" className="auth-btn" disabled={loading}>
            {loading ? <span className="auth-btn__spinner" /> : null}
            {loading ? "Signing in…" : "Login"}
          </button>
        </form>

        <div className="auth-card__footer">
          <p>
            Don't have an account?{" "}
            <button className="auth-link" onClick={onGoRegister}>
              Register here
            </button>
          </p>
        </div>
      </div>
    </div>
  );
}

export default LoginPage;
